# Databricks notebook source
# MAGIC %md
# MAGIC # LLM-as-a-Judge Evaluator
# MAGIC This notebook runs periodically to evaluate the traces generated by the Supply Chain Agent.
# MAGIC It reads from the Inference Tables, uses MLflow Evaluate with an LLM judge, and writes the scores back to a Delta table.

# COMMAND ----------

import os
import mlflow
import pandas as pd

# Get config from env
experiment_name = os.getenv("MLFLOW_EXPERIMENT_NAME", "/Shared/supply_chain_agent")
catalog_schema = os.getenv("CATALOG_SCHEMA", "taylor_hanson_build_catalog.supply_chain_schema")

# 1. Load recent traces from MLflow experiment
experiment = mlflow.get_experiment_by_name(experiment_name)
if experiment is None:
    raise ValueError(f"Experiment '{experiment_name}' not found.")

traces = mlflow.search_traces(
    experiment_ids=[experiment.experiment_id],
    max_results=100
)

print(f"Found {len(traces)} traces from experiment: {experiment_name}")

# Build evaluation DataFrame from traces
if not traces.empty:
    df_eval = traces[["request", "response"]].dropna().reset_index(drop=True)
    df_eval.columns = ["inputs", "response"]
    print(f"Prepared {len(df_eval)} traces for evaluation")
else:
    df_eval = pd.DataFrame()
    print("No traces found.")

# COMMAND ----------

# 2. Run LLM-as-a-Judge using MLflow Evaluate
if df_eval.empty:
    print("No traces found to evaluate. Skipping evaluation.")
else:
    # We use a judge model configured via AI Gateway
    judge_model = "endpoints:/databricks-meta-llama-3-70b-instruct"

    # Define custom metrics if needed, or use built-in
    relevance_metric = mlflow.metrics.genai.answer_relevance(model=judge_model)
    professionalism_metric = mlflow.metrics.genai.make_genai_metric(
        name="professionalism",
        definition="Whether the response is professional and appropriate for a business setting.",
        grading_prompt="Score 1 if professional, 0 if not.",
        model=judge_model,
        parameters={"temperature": 0.0}
    )

    with mlflow.start_run(run_name="passive_llm_judge"):
        results = mlflow.evaluate(
            data=df_eval,
            model_type="text",
            predictions="response",
            evaluators="default",
            extra_metrics=[relevance_metric, professionalism_metric]
        )

# COMMAND ----------

# 3. Write scores back to Delta table
if not df_eval.empty:
    eval_results_df = results.tables["eval_results_table"]

    spark_df = spark.createDataFrame(eval_results_df)
    spark_df.write.mode("append").saveAsTable(f"{catalog_schema}.agent_eval_scores")

    print("Successfully evaluated traces and saved scores.")
